// context
typedef struct {
    char *data;
    int   len;
} Buffer;

Buffer *make_buffer(int len) {
    if (len <= 0) return NULL;
    Buffer *b = malloc(sizeof(Buffer));
    b->data = malloc(len);
    return b;
}

// target function
void write_record(int len, int offset, char val) {
    Buffer *b = make_buffer(len);
    b->data[offset] = val;
    free(b->data);
    free(b);
}

